window.__QUIZ_DATA__=[{"id":"theory>Agricultural Science Practical>2005>1>a>i","subject":"Agricultural Science Practical","year":"2005","type":"Practical","sub_label":"i","group":"","topic":"AGRICULTURAL ECOLOGY : ROCK FORMATION","question":"Classify specimens B and D according to their mode of formation.","images":[],"marking_scheme":"Classification of specimens B and D according to their mode of formation are as follows:    B - Sedimentary rock  D - Igneous rock","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2005>1>a>ii","subject":"Agricultural Science Practical","year":"2005","type":"Practical","sub_label":"ii","group":"","topic":"AGRICULTURAL ECOLOGY : ROCK FORMATION","question":"Name two other rocks for each mode of formation","images":[],"marking_scheme":"Other examples of each rock types are:    B - Limestone, shale, coal, common salt, gypsum, breccia, conglomerate.  D - Basalt, gabro, diorite, pumice","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2005>1>b","subject":"Agricultural Science Practical","year":"2005","type":"Practical","sub_label":"b","group":"","topic":"AGRICULTURAL ECOLOGY : ROCK FORMATION","question":"Given three differences between specimens B and D","images":[],"marking_scheme":"Differences:    B has layers/ stata while D does not have layers.  Particles are loosely held together in specimen B but not so in specimen D.  Particles in specimen B are fine while those in D are coarse.  Specimen B is lighter than specimen D.  B is prone to erosion while D is resistant to.  B is fairly soft while D is hard.  D is crystaline while B is not.  B is fossilized while D is not.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2005>1>c","subject":"Agricultural Science Practical","year":"2005","type":"Practical","sub_label":"c","group":"","topic":"AGRICULTURAL ECOLOGY : ROCK FORMATION","question":"State three uses of specimen D in agriculture.","images":[],"marking_scheme":"Uses of specimen D in agriculture are:    In control of erosion.  Building farm structures.  For decorations (external and interior).  Farm road construction.  Grinding/sharpening farm tools.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2005>1>d","subject":"Agricultural Science Practical","year":"2005","type":"Practical","sub_label":"d","group":"","topic":"AGRICULTURAL ECOLOGY : ROCK FORMATION","question":"State five disadvantages of an abundance of specimen D on a farmland.","images":[],"marking_scheme":"Disadvantages of abundance of specimen D on a farmland;    Increase coast of tillage operations.  Predisposes man and animals to injury.  Reduces amount of arable land.  Implements wear out fast.  Increases drudgery.  Hideout for reptiles and rodents.  Prevents root penetration.  Makes tillage operations difficult.  Disturbs the growth of plants.  Tends to increase ambient temperature during hot season.  Hinders the activities of micro and macro-organisms.","marks":"1","difficulty":"3"},{"id":"theory>Agricultural Science Practical>2005>2>a","subject":"Agricultural Science Practical","year":"2005","type":"Practical","sub_label":"a","group":"","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"Name three other equipment that can perform similar functions as specimen F.","images":[],"marking_scheme":"Other equipment that can perform similar functions as specimen F are:    Motorized sprayer.  Electrodyn sprayer.  Boom sprayer.  Hand sprayer.  Uitra low volume sprayer.  Tractor-mounted / helicopter / aeroplane - mounted sprayer.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2005>2>b","subject":"Agricultural Science Practical","year":"2005","type":"Practical","sub_label":"b","group":"","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"State five safety precautions to be taken when using specimen F.","images":[],"marking_scheme":"Safety precautions to be taken when using specimen F:    Ensure the equipment is in good condition before starting.  Read and follow instructions on the chemical container before operations begin.  Wear protective clothing when spraying.  Avoid smoking, eating or drinking while spraying.  Do not blow blocked nozzles with mouth.  Do not spray against the wind.  Avoid walking/spraying into areas freshly sprayed.  Do not spray in hot afternoons.  Wash body thoroughly after use.  Avoid spillage of chem\u00edcal in wrong place","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2005>2>c","subject":"Agricultural Science Practical","year":"2005","type":"Practical","sub_label":"c","group":"","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"Describe how specimen F is used","images":[],"marking_scheme":"How specimen F is used:    Pour a measured quantity of water into tank.  Add correct amount of chemical to water in tank and miss well.  cover the tank properly with the lid.  Pump to raise pressure within tank.  Mount sprayer on the back.  Spray while walking away from sprayed area.  Direct nozzle to the area to be sprayed.  Pressure in tank is maintained by occasional pumping.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2005>2>d","subject":"Agricultural Science Practical","year":"2005","type":"Practical","sub_label":"d","group":"","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"State three faults that may develop in specimen F when in use.","images":[],"marking_scheme":"Faults that may arise while using specimen F are:    Clogging of nozzles.  Pressure could leak from pressure chamber.  Leakage of chemical from hose or tank.  Hose could rupture.  Nozzle could get dismantled/disorganize.  Pump lever may be broken or faulty","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2005>3>a","subject":"Agricultural Science Practical","year":"2005","type":"Practical","sub_label":"a","group":"","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS~~CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Identify each specimen G, H, I, and K.","images":[],"marking_scheme":"ldentification of specimens:    G = Pepper fruit.  H = Onion bulb,  I = Cotton seeds,  K = Okro","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2005>3>b","subject":"Agricultural Science Practical","year":"2005","type":"Practical","sub_label":"b","group":"","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"Name two uses of each of specimens G and H.","images":[],"marking_scheme":"Uses of specimens G and H are:    Specimen G ;    As Spice for food.  As insect repellant in stored foodstuff.  Produce/preservative.  Medicinal uses.  As yolk colourant","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2005>3>c","subject":"Agricultural Science Practical","year":"2005","type":"Practical","sub_label":"c","group":"","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"Name the group of crops to which each of specimens H, I, and K belong.","images":[],"marking_scheme":"Groups of crops:    H- spice.  I - fibre.  K -vegetable","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2005>3>d","subject":"Agricultural Science Practical","year":"2005","type":"Practical","sub_label":"d","group":"","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Describe the planting operations for specimen G","images":[],"marking_scheme":"Planting operations for planting specimen G are:    Clear and plough the land.  Separate seeds from fruits.  Prepare nursery beds.  Plant seeds (about 1 cm deep) in the nursery.  While in nursery, weed, shade, and apply water.  Transplant to the field by removing seedling with a ball of soil around roots after 3-5 weeks.  Transplant in the evening or early in the morning. When well established, apply fertilizer and insecticides if necessary.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2005>3>e","subject":"Agricultural Science Practical","year":"2005","type":"Practical","sub_label":"e","group":"","topic":"CROP PROTECTION : PESTS OF CROPS","question":"Name two pests of specimen H.","images":[],"marking_scheme":"Maggots, crickets, cutwarms, eelworms, thrips are pests of specimen H.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2005>4>a>i","subject":"Agricultural Science Practical","year":"2005","type":"Practical","sub_label":"i","group":"","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"identify specimen M.","images":[],"marking_scheme":"Specimen M; Reproductive system of a hen or female bird. Oviduct of a hen.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2005>4>a>ii","subject":"Agricultural Science Practical","year":"2005","type":"Practical","sub_label":"ii","group":"","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"Draw and label specimen M.","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2005>4>b","subject":"Agricultural Science Practical","year":"2005","type":"Practical","sub_label":"b","group":"","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"Explain the role of each of the parts of specimen M you have labeled in carrying out its function.","images":[],"marking_scheme":"Role of each part in the organ for carrying out its function:    Funnel/infundibulum - Receives ova and site for fertilization of ova.  Magnum - Albumin or egg white on yolk chalaza produced.  Isthmus - Secretes materials for shell membranes, determines shape of egg.  Uterus - Water and minerals are added to albumin, secretes calcium carbonate for egg shell.  Vagina - Site for deposition of sperm - passage for egg.  Cloaca - Complete egg passes from uterus to cloaca where it is expelled.","marks":"1","difficulty":"2"}];